const fetchUsers = async (term) => {
  setLoading(true);
  setError(null);
  try {
    const response = await fetch(`/api/users?search=${encodeURIComponent(term)}`);
    if (!response.ok) throw new Error('Erreur réseau');
    const data = await response.json();
    setUsers(data);
  } catch (err) {
    setError(err.message);
  } finally {
    setLoading(false);
  }
};

let abortController = null;

const fetchUsers = async (term) => {
  if (abortController) {
    abortController.abort();
  }
  abortController = new AbortController();
  setLoading(true);
  try {
    const response = await fetch(`/api/users?search=${term}`, {
      signal: abortController.signal
    });
    const data = await response.json();
    setUsers(data);
    setError(null);
  } catch (err) {
    if (err.name !== 'AbortError') {
      setError(err.message);
    }
  } finally {
    setLoading(false);
  }
};

function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const result = await response.json();
      setData(result);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [url]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  return { data, loading, error, refetch: fetchData };
}

useEffect(() => {
  const abortController = new AbortController();

  const fetchData = async () => {
    try {
      const response = await fetch(url, { signal: abortController.signal });
      const result = await response.json();
      setData(result);
    } catch (err) {
      if (err.name !== 'AbortError') setError(err.message);
    }
  };

  fetchData();
  return () => abortController.abort();
}, [url]);

function Weather() {
  const [weather, setWeather] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchWeather = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/weather/douala');
      if (!res.ok) throw new Error('Erreur serveur');
      const data = await res.json();
      setWeather(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchWeather(); }, [fetchWeather]);

  if (loading) return <div>Chargement de la météo...</div>;
  if (error) return (
    <div>
      <p>Erreur : {error}</p>
      <button onClick={fetchWeather}>Réessayer</button>
    </div>
  );
  return <div>Température : {weather.temp}°C</div>;
}
